export function getSitesByState(stateCode: string): CampSite[] {
  return ALL_SITES.filter((s) => s.state === stateCode);
}

export function getSitesByCategory(category: string): CampSite[] {
  return ALL_SITES.filter((s) => s.category === category);
}

export function getFreeSites(): CampSite[] {
  return ALL_SITES.filter((s) => s.pricePerNight === null);
}

export function searchSites(query: string): CampSite[] {
  const lower = query.toLowerCase();
  return ALL_SITES.filter(
    (s) =>
      s.name.toLowerCase().includes(lower) ||
      s.city.toLowerCase().includes(lower) ||
      s.description.toLowerCase().includes(lower)
  );
}

